import axiosInstance from "@/api/axios/axiosInstance";
import { toast } from "sonner";

// Types
export interface FacebookUser {
  id: string;
  name: string;
  email: string;
}

export interface FacebookConnectionStatus {
  isConnected: boolean;
  facebookUser?: FacebookUser;
  connectedAt?: string;
  expiresAt?: string;
}

export interface FacebookPage {
  id: string;
  name: string;
  category?: string;
  access_token?: string;
}

export interface FacebookLeadForm {
  id: string;
  name: string;
  status: string;
  page_id?: string;
  form_id?: string;
  questions?: Array<{
    key: string;
    label: string;
    type: string;
    options?: string[];
  }>;
}

export interface FacebookLead {
  id: string;
  created_time: string;
  field_data: Array<{
    name: string;
    values: string[];
  }>;
}

// Facebook OAuth URL generation
export function generateFacebookOAuthUrl(): string {
  const clientId = import.meta.env.VITE_FACEBOOK_APP_ID;
  const redirectUri = encodeURIComponent(import.meta.env.VITE_FACEBOOK_REDIRECT_URI || `${window.location.origin}/webhooks`);
  const scope = encodeURIComponent('pages_manage_metadata,leads_retrieval,pages_read_engagement');
  const state = Math.random().toString(36).substring(2, 15);
  
  return `https://www.facebook.com/v18.0/dialog/oauth?client_id=${clientId}&redirect_uri=${redirectUri}&scope=${scope}&response_type=code&state=${state}`;
}

// Connect Facebook account
export async function connectFacebookAccount(code: string, state?: string) {
  try {
    const res = await axiosInstance.post("/api/auth/facebook/connect", {
      code,
      state
    });
    
    if (res.data.success) {
      toast.success("Facebook account connected successfully!");
      return res.data.data;
    }
    
    throw new Error(res.data.message || "Failed to connect Facebook account");
  } catch (error: any) {
    console.error("Error connecting Facebook account:", error);
    const message = error.response?.data?.message || "Failed to connect Facebook account";
    toast.error(message);
    throw error;
  }
}

// Get Facebook connection status
export async function getFacebookConnectionStatus(): Promise<FacebookConnectionStatus> {
  try {
    const res = await axiosInstance.get("/api/auth/facebook/status");
    return res.data.data;
  } catch (error: any) {
    console.error("Error getting Facebook status:", error);
    return { isConnected: false };
  }
}

// Disconnect Facebook account
export async function disconnectFacebookAccount() {
  try {
    const res = await axiosInstance.delete("/api/auth/facebook/disconnect");
    
    if (res.data.success) {
      toast.success("Facebook account disconnected successfully!");
      return true;
    }
    
    throw new Error(res.data.message || "Failed to disconnect Facebook account");
  } catch (error: any) {
    console.error("Error disconnecting Facebook account:", error);
    const message = error.response?.data?.message || "Failed to disconnect Facebook account";
    toast.error(message);
    throw error;
  }
}

